(window.webpackJsonp=window.webpackJsonp||[]).push([[10],{1701:function(s){s.exports=JSON.parse('{"content":"<p>\u5f53\u521b\u5efa\u51fa\u4e00\u4e2a\u7269\u4f53\uff0c\u6211\u4eec\u60f3\u7ed9\u4ed6\u52a0\u70b9\u52a8\u753b</p>\\n<p><code>threejs</code>\u7684\u7269\u4f53\u5305\u542b\u4e86<code>rotation</code>\u63a7\u5236\u65cb\u8f6c\uff0c<code>position</code>\u548c<code>translateOnAxis</code>\u63a7\u5236\u4f4d\u7f6e</p>\\n<pre class=\\"hljs\\"><code>obj.rotation.set(<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>)\\nobj.position.set(<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>)\\nobj.translateOnAxis(<span class=\\"hljs-string\\">\'x\'</span>,<span class=\\"hljs-number\\">10</span>)\\n</code></pre>\\n<p>\u7136\u540e\u53ef\u4ee5\u901a\u8fc7<code>requestAnimationFrame</code>\u6765\u6e32\u67d3\u52a8\u753b</p>\\n<pre class=\\"hljs\\"><code><span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">animate</span>(<span class=\\"hljs-params\\"></span>)</span>{\\n    obj.rotation.x=<span class=\\"hljs-built_in\\">Math</span>.PI / <span class=\\"hljs-number\\">180</span>\\n    requestAnimationFrame(animate)\\n}\\nrequestAnimationFrame(animate)\\n</code></pre>\\n<p>\u95ee\u9898\uff1a</p>\\n<p>\u7269\u4f53\u539f\u70b9\uff0c\u9ed8\u8ba4\u7269\u4f53\u539f\u70b9\u662f\u7269\u4f53\u7684\u4e2d\u5fc3\u70b9\uff0c\u5982\u679c\u8ba9\u7269\u4f53\u7ed5\u7740\u67d0\u4e00\u4e2a\u70b9\uff0c\u800c\u975e\u4e2d\u5fc3\u70b9\u6765\u8fd0\u52a8</p>\\n<p>\u8fd9\u91cc\u53ef\u4ee5\u4f7f\u7528<code>translateOnAxis</code>\u6765\u5904\u7406\uff0c<code>translateOnAxis</code>\u662f\u4e0d\u6539\u53d8\u7269\u4f53\u539f\u70b9\u7684\u79fb\u52a8\uff0c<code>position</code>\u662f\u6539\u53d8\u7269\u4f53\u539f\u70b9\u7684\u79fb\u52a8\u3002</p>\\n<p>\u5f53\u4e00\u4e2a\u7269\u4f53\u4f7f\u7528<code>position</code>\u6cbf\u7740<code>x</code>\u8f74\u79fb\u52a8<code>10</code>\uff0c\u90a3\u4e48\u5b83\u7684\u539f\u70b9\u4ece\u539f\u6765\u7684<code>(0,0,0)</code>\u6765\u5230\u4e86<code>(10,0,0)</code>\\n\u518d\u4f7f\u7528<code>translateOnAxis</code>\u6cbf\u7740<code>x</code>\u8f74\u79fb\u52a8<code>-10</code>\uff0c\u5b83\u56de\u5230\u4e86\u521d\u59cb\u70b9<code>(0,0,0)</code>\uff0c\u4f46\u539f\u70b9\u4e0d\u4f1a\u6539\u53d8\uff0c\u8fd8\u662f<code>(10,0,0)</code></p>\\n<p>\u8fd9\u662f\u518d\u4f7f\u7528<code>rotation</code>\u8fdb\u884c\u65cb\u8f6c\u52a8\u753b\u7684\u65f6\u5019\uff0c\u539f\u70b9\u5c31\u5230\u4e86<code>(10,0,0)</code></p>\\n<pre class=\\"hljs\\"><code>obj.position.x=<span class=\\"hljs-number\\">10</span>\\nobj.translateOnAxis(<span class=\\"hljs-string\\">\'x\'</span>,<span class=\\"hljs-number\\">-10</span>)\\nobj.rotation.x=<span class=\\"hljs-built_in\\">Math</span>.PI / <span class=\\"hljs-number\\">2</span>\\n</code></pre>\\n"}')}}]);